            minNode[rootV.toInt()] = minOf(minNode[rootU.toInt()], minNode[rootV.toInt()])
            if (rank[rootU.toInt()] == rank[rootV.toInt()]) {
                rank[rootV.toInt()]++
            }
        }
    }

    // Initialize DSU
    for (conn in connections) {
        val u = conn[0]
        val v = conn[1]
        union(u, v)
    }

    // Reset minNode for online nodes
    for (i in 1..c.toInt()) {
        val root = find(i.toLong())
        if (online[i] && minNode[root.toInt()] > i.toLong()) {
            minNode[root.toInt()] = i.toLong()
        }
    }

    val result = mutableListOf<Long>()
    for (query in queries) {
        val type = query[0]
        val x = query[1]
        if (type == 1L) {
            val root = find(x)
            if (online[x.toInt()]) {
                result.add(x)
            } else {
                var minOnline = Long.MAX_VALUE
                // We need to find the minimal online node in the same component
                // But with large constraints, we need a better way
                // So we use the minNode array, but need to ensure it's updated correctly
                if (minNode[root.toInt()] != Long.MAX_VALUE && online[minNode[root.toInt()].toInt()]) {
                    result.add(minNode[root.toInt()])
                } else {
                    // Need to find the minimal online node in the component
                    // This is not efficient for large components, but for the sake of this problem, we proceed
                    var found = false
                    for (i in 1..c.toInt()) {
                        if (find(i.toLong()) == root && online[i]) {
                            if (i.toLong() < minOnline) {
                                minOnline = i.toLong()
                                found = true
                            }
                        }
