                        result.add(minOnline)
                        minNode[root.toInt()] = minOnline
                    } else {
                        result.add(-1)
                        minNode[root.toInt()] = Long.MAX_VALUE
                    }
                }
            }
        } else if (type == 2L) {
            online[x.toInt()] = false
            val root = find(x)
            if (minNode[root.toInt()] == x) {
                // Need to find the next minimal online node in the component
                var minOnline = Long.MAX_VALUE
                for (i in 1..c.toInt()) {
                    if (find(i.toLong()) == root && online[i]) {
                        if (i.toLong() < minOnline) {
                            minOnline = i.toLong()
                        }
                    }
                }
                minNode[root.toInt()] = if (minOnline == Long.MAX_VALUE) Long.MAX_VALUE else minOnline
            }
        }
    }

    return result.toTypedArray()
